struct Stock: Codable, Identifiable, Equatable {
    let id: String
    let symbol: String
    let name: String
    var currentPrice: Double
    var previousClose: Double
    var dayHigh: Double
    var dayLow: Double
    var volume: Int
    var changePercent: Double {
        guard previousClose > 0 else { return 0 }
        return ((currentPrice - previousClose) / previousClose) * 100
    }
    var change: Double {
        return currentPrice - previousClose
    }
}

struct Position: Codable, Identifiable {
    let id: String
    let symbol: String
    let name: String
    var quantity: Double
    var averageCost: Double
    var currentPrice: Double
    var marketValue: Double { quantity * currentPrice }
    var totalCost: Double { quantity * averageCost }
    var profitLoss: Double { marketValue - totalCost }
    var profitLossPercent: Double {
        guard totalCost > 0 else { return 0 }
        return (profitLoss / totalCost) * 100
    }
}

struct Portfolio: Codable {
    var positions: [Position]
    var cashBalance: Double
    var totalValue: Double {
        positions.reduce(cashBalance) { $0 + $1.marketValue }
    }
    var totalProfitLoss: Double {
        positions.reduce(0) { $0 + $1.profitLoss }
    }
}

