enum APIError: Error, LocalizedError {
    case invalidURL
    case networkError(Error)
    case decodingError(Error)
    case unauthorized
    case rateLimited
    case serverError(Int)
    case insufficientFunds
    case invalidOrder
    case marketClosed
    case unknown

    var errorDescription: String? {
        switch self {
        case .invalidURL: return "Invalid URL"
        case .networkError(let error): return "Network error: \(error.localizedDescription)"
        case .decodingError: return "Failed to process response"
        case .unauthorized: return "Authentication required"
        case .rateLimited: return "Too many requests. Please wait."
        case .serverError(let code): return "Server error (\(code))"
        case .insufficientFunds: return "Insufficient funds"
        case .invalidOrder: return "Invalid order parameters"
        case .marketClosed: return "Market is currently closed"
        case .unknown: return "An unknown error occurred"
        }
    }
}

class SecureTokenManager {
    static let shared = SecureTokenManager()
    private let keychainService = "com.tradingapp.keychain"

    private init() {}

    func saveToken(_ token: String, forKey key: String) {
        let data = Data(token.utf8)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: key,
            kSecValueData as String: data
        ]
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }

    func getToken(forKey key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status == errSecSuccess, let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }

    func deleteToken(forKey key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }

    func generateHMAC(for message: String, using key: String) -> String {
        let keyData = SymmetricKey(data: Data(key.utf8))
        let signature = HMAC<SHA256>.authenticationCode(for: Data(message.utf8), using: keyData)
        return Data(signature).base64EncodedString()
    }
}

class APIClient {
    static let shared = APIClient()
    private let baseURL = "https://api.tradingplatform.com/v1"
    private let session: URLSession
    private let tokenManager = SecureTokenManager.shared
    private let decoder: JSONDecoder
    private var rateLimitRemaining = 100
    private var rateLimitResetDate: Date?

    private init() {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 15
        config.timeoutIntervalForResource = 30
        config.waitsForConnectivity = true
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        session = URLSession(configuration: config)

        decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
    }

    private func createRequest(endpoint: String, method: String = "GET", body: Data? = nil) throws -> URLRequest {
        guard let url = URL(string: "\(baseURL)\(endpoint)") else {
            throw APIError.invalidURL
        }

        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        if let token = tokenManager.getToken(forKey: "access_token") {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }

        let timestamp = String(Int(Date().timeIntervalSince1970))
        request.setValue(timestamp, forHTTPHeaderField: "X-Timestamp")

        if let apiSecret = tokenManager.getToken(forKey: "api_secret") {
            let message = "\(method)\(endpoint)\(timestamp)"
            let signature = tokenManager.generateHMAC(for: message, using: apiSecret)
            request.setValue(signature, forHTTPHeaderField: "X-Signature")
        }

        request.httpBody = body

        return request
    }

    func performRequest<T: Decodable>(endpoint: String, method: String = "GET", body: Encodable? = nil) async throws -> T {
        if rateLimitRemaining <= 0, let resetDate = rateLimitResetDate, Date() < resetDate {
            throw APIError.rateLimited
        }

        var bodyData: Data?
        if let body = body {
            let encoder = JSONEncoder()
            encoder.dateEncodingStrategy = .iso8601
            bodyData = try encoder.encode(body)
        }

        let request = try createRequest(endpoint: endpoint, method: method, body: bodyData)
        let (data, response) = try await session.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.unknown
        }

        if let remaining = httpResponse.value(forHTTPHeaderField: "X-RateLimit-Remaining") {
            rateLimitRemaining = Int(remaining) ?? 100
        }
        if let reset = httpResponse.value(forHTTPHeaderField: "X-RateLimit-Reset") {
            rateLimitResetDate = Date(timeIntervalSince1970: Double(reset) ?? 0)
        }

        switch httpResponse.statusCode {
        case 200...299:
            do {
                return try decoder.decode(T.self, from: data)
            } catch {
                throw APIError.decodingError(error)
            }
        case 401:
            throw APIError.unauthorized
        case 429:
            throw APIError.rateLimited
        case 500...599:
            throw APIError.serverError(httpResponse.statusCode)
        default:
            throw APIError.unknown
        }
    }
}

